import{_}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as e,c as p,h as t}from"./app.814dec7b.js";const a={},c=t('<h1 id="\u5148\u77E5-\u6587\u660E\u53F2\u5EFA\u7FA4\u4E3E\u610F\u548C\u5B97\u65E8" tabindex="-1"><a class="header-anchor" href="#\u5148\u77E5-\u6587\u660E\u53F2\u5EFA\u7FA4\u4E3E\u610F\u548C\u5B97\u65E8" aria-hidden="true">#</a> \u5148\u77E5-\u6587\u660E\u53F2\u5EFA\u7FA4\u4E3E\u610F\u548C\u5B97\u65E8</h1><p>\u5168\u7F8E\u8D5B\u4FE9\u76EE\u95EE\u5019\u5927\u5BB6\uFF01</p><p>\u6211\u770B\u4E86\u4E00\u4E0B\u8FD9\u4E2A\u7FA4\uFF0C\u6709\u5F88\u591A\u90FD\u662F\u719F\u6089\u7684\u670B\u53CB\u548C\u5144\u5F1F\u59D0\u59B9\uFF0C\u6709\u4E00\u4E9B\u53EF\u80FD\u8FD8\u4E0D\u8BA4\u8BC6\uFF0C\u6709\u53EF\u80FD\u662F\u6211\u7684\u5E08\u957F\uFF0C\u6216\u8005\u662F\u5B66\u672F\u4E0A\u7684\u540C\u9053\u3002\u4E0D\u7BA1\u600E\u4E48\u6837\uFF0C\u8FD9\u662F\u4E00\u4E2A\u7FA4\uFF0C\u4E5F\u4E0D\u662F\u4E00\u4E2A\u591A\u4E48\u6B63\u5F0F\u7684\u4E00\u4E2A\u5B66\u672F\u5E73\u53F0\uFF0C\u5927\u5BB6\u53EF\u4EE5\u968F\u4FBF\u7684\u4EA4\u6D41\u3002\u5176\u5B9E\u9A6C\u8427\u5144\u5F1F\u5EFA\u8FD9\u4E2A\u7FA4\u6709\u4E00\u4E2A\u521D\u8877\uFF0C\u4ED6\u89C9\u5F97\u6211\u5173\u6CE8\u7684\u8FD9\u4E2A\u8BDD\u9898\u5F88\u6709\u610F\u601D\uFF0C\u89C9\u5F97\u5982\u679C\u53EF\u4EE5\u7684\u8BDD\uFF0C\u548C\u5927\u5BB6\u4E00\u8D77\u5206\u4EAB\u4E00\u4E0B\u3002</p><p>\u5728\u4ECA\u5929\u8FD9\u4E2A\u4E0D\u662F\u591A\u4E48\u9002\u5B9C\u7684\u4E00\u4E2A\u65F6\u673A\uFF0C\u5EFA\u7FA4\u6765\u548C\u5927\u5BB6\u4E00\u8D77\u4EA4\u6D41\uFF0C\u6211\u4E5F\u6709\u81EA\u5DF1\u7684\u4E00\u4E9B\u60F3\u6CD5\uFF0C\u56E0\u4E3A\u6BD5\u7ADF\u4F5C\u4E3A\u6211\u4EEC\u5728\u4E2D\u56FD\u8FD9\u6837\u4E00\u4E2A\u73AF\u5883\u5F53\u4E2D\uFF0C\u610F\u601D\u5170\u65B9\u9762\u7684\u4E00\u4E9B\u5B66\u672F\u6216\u601D\u60F3\u95EE\u9898\uFF0C\u4E0D\u662F\u5F88\u6D3B\u8DC3\uFF0C\u7B2C\u4E8C\u4E5F\u975E\u5E38\u5C01\u95ED\u751A\u81F3\u5F88\u5B64\u7ACB\u3002</p><p>\u897F\u65B9\u7684\u5B66\u672F\uFF0C\u5305\u62EC\u4E2D\u56FD\u5728\u5185\uFF0C\u6709\u4E00\u4E2A\u4F20\u7EDF\u3002\u5C31\u662F\u67D0\u4E00\u4E2A\u4EBA\u6709\u4E00\u4E2A\u4E3B\u9898\uFF0C\u6216\u8005\u60F3\u8981\u5199\u4E00\u4E2A\u89C2\u70B9\u3002\u4ED6\u4EEC\u4F1A\u628A\u81EA\u5DF1\u7684\u4E66\u7A3F\u6837\u672C\u53D1\u7ED9\u540C\u9053\uFF0C\u6216\u8005\u719F\u6089\u7684\u670B\u53CB\u8BA9\u4ED6\u4EEC\u8FDB\u884C\u8BA8\u8BBA\uFF0C\u7136\u540E\u63D0\u51FA\u4E00\u4E9B\u4E0D\u540C\u7684\u5EFA\u8BAE\u3002\u6211\u89C9\u5F97\u8FD9\u4E2A\u662F\u975E\u5E38\u6709\u5FC5\u8981\u7684\uFF0C\u95ED\u95E8\u9020\u8F66\uFF0C\u5305\u62EC\u4F60\u81EA\u5DF1\u53BB\u5199\u3001\u53BB\u601D\u8003\uFF0C\u6709\u65F6\u5019\u662F\u5F88\u5371\u9669\u7684\u4E00\u4EF6\u4E8B\u60C5\uFF0C\u5C24\u5176\u6211\u4EEC\u4F5C\u4E3A\u4E00\u4E2A\u5929\u542F\u5B97\u6559\u7684\u4FE1\u4EF0\uFF0C\u5728\u4ECA\u5929\u8FD9\u6837\u4E00\u4E2A\u4E16\u4FD7\u5316\u7684\u6216\u8005\u5168\u7403\u5316\u7684\u591A\u5143\u6587\u660E\u548C\u6587\u5316\u5171\u5904\u7684\u4E00\u4E2A\u65F6\u4EE3\u5F53\u4E2D\uFF0C\u5173\u8D77\u95E8\u505A\u81EA\u5DF1\u7684\u8FD9\u4E2A\u5B66\u672F\u4E5F\u7F62\uFF0C\u6216\u8005\u8BA8\u8BBA\u95EE\u9898\u4E5F\u7F62\uFF0C\u5176\u5B9E\u4E5F\u662F\u4E00\u4EF6\u975E\u5E38\u5371\u9669\u7684\u4E00\u4EF6\u4E8B\u60C5\u3002</p><p>\u6211\u8BB0\u5F97\u4F59\u82F1\u65F6\u7684\u5F1F\u5B50\u738B\u6C4E\u68EE\uFF0C\u66FE\u7ECF\u6709\u4E00\u672C\u513F\u4E66\uFF0C\u540D\u5B57\u5E94\u8BE5\u5C31\u662F\u300A\u5929\u624D\u4E3A\u4F55\u6210\u7FA4\u800C\u6765\u300B\u3002\u4ED6\u5C31\u8C08\u5230\u4E00\u4E2A\u975E\u5E38\u6709\u8DA3\u73B0\u8C61\uFF0C\u5C31\u662F\u67D0\u4E00\u4E2A\u65F6\u6BB5\uFF0C\u603B\u4F1A\u51FA\u73B0\u4E00\u4E9B\u7480\u74A8\u7684\u5929\u624D\u822C\u7684\u5B66\u8005\uFF0C\u5C31\u50CF\u6316\u77FF\u4E00\u6837\uFF0C\u4E00\u7A9D\u513F\u4E00\u7A9D\u513F\u7684\u51FA\u73B0\uFF0C\u4ED6\u5C31\u5BF9\u8FD9\u4E2A\u73B0\u8C61\u5F88\u5174\u8DA3\u3002\u6700\u540E\uFF0C\u4ED6\u53D1\u73B0\u81F3\u5C11\u662F\u4E00\u4E2A\u539F\u56E0\uFF0C\u5C31\u5BFC\u81F4\u4E00\u4E2A\u65F6\u4EE3\u548C\u5708\u5B50\u6709\u5F88\u591A\u5927\u5E08\u7EA7\u7684\u4EBA\u7269\u4EA7\u751F\uFF0C\u4ED6\u4EEC\u4F1A\u5728\u4E00\u8D77\u8FDB\u884C\u5F7C\u6B64\u5B66\u95EE\u4E4B\u95F4\u7684\u4EA4\u6D41\uFF0C\u5B66\u95EE\u662F\u5728\u4EA4\u6D41\u5F53\u4E2D\u7CBE\u8FDB\u548C\u5347\u534E\u7684\u3002\u6BCB\u5EB8\u7F6E\u7591\uFF0C\u65E9\u671F\u4F20\u7EDF\u793E\u4F1A\uFF0C\u51E0\u4E4E\u6240\u6709\u7684\u5B66\u672F\u90FD\u662F\u4EE5\u8BBA\u8FA9\u548C\u4EA4\u6D41\u7684\u5F62\u5F0F\uFF0C\u78B0\u649E\u51FA\u601D\u60F3\u7684\u706B\u82B1\u7684\u3002</p><p>\u5173\u4E8E\u5BF9\u610F\u601D\u5170\u7684\u5404\u65B9\u9762\u7684\u77E5\u8BC6\u7684\u63A2\u8BA8\uFF0C\u5176\u5B9E\u6211\u8BA4\u4E3A\u8FD8\u6CA1\u6709\u5F00\u59CB\u3002\u6240\u4EE5\uFF0C\u5373\u4F7F\u5728\u4ECA\u5929\uFF0C\u8FD9\u6837\u4E00\u4E2A\u4E0D\u662F\u591A\u4E48\u5408\u65F6\u5B9C\u7684\u80CC\u666F\u4E0B\uFF0C\u6211\u89C9\u5F97\u8FD8\u662F\u6709\u5FC5\u8981\u548C\u5144\u5F1F\u59CA\u59B9\u4EEC\u8FDB\u884C\u4EA4\u6D41\u3002\u867D\u7136\u6709\u4E9B\u5144\u5F1F\u59CA\u59B9\u53EF\u80FD\u5728\u8FD9\u4E2A\u65B9\u9762\u4E0D\u662F\u5F88\u5174\u8DA3\uFF0C\u6216\u8005\u6CA1\u6709\u4E13\u95E8\u513F\u7684\u7814\u7A76\uFF0C\u4F46\u662F\u6211\u89C9\u5F97\uFF0C\u5927\u5BB6\u7684\u77E5\u8BC6\u91CF\u8DB3\u4EE5\u8BA9\u6211\u4EEC\u4E4B\u95F4\uFF0C\u80FD\u6709\u4E00\u4E2A\u6709\u76CA\u7684\u4E92\u52A8\u548C\u4EA4\u6D41\u3002</p><p>\u9A6C\u8427\u5144\u5F1F\u53EF\u80FD\u628A\u300A\u6211\u4EEC\u300B\u4E0A\u53D1\u8868\u7684\u4E00\u4E9B\u6587\u7AE0\uFF0C\u7ED9\u5927\u5BB6\u4E00\u90E8\u5206\u5144\u5F1F\u59D0\u59B9\u770B\u4E86\uFF0C\u90A3\u53EA\u662F\u4E00\u4E2A\u975E\u5E38\u7C97\u7565\u7684\u4E00\u4E2A\u7EB2\u8981\uFF0C\u5F88\u591A\u95EE\u9898\u5176\u5B9E\u6839\u672C\u6CA1\u6709\u8FDB\u4E00\u6B65\u7684\u53BB\u6316\u6398\uFF0C\u94F6\u6C99\u5B89\u62C9\uFF0C\u6709\u673A\u4F1A\u6211\u4EEC\u540E\u9762\u6162\u6162\u8C08\u8BBA\u3002\u8FD9\u4E9B\u95EE\u9898\u4E5F\u4E0D\u662F\u4E00\u65F6\u534A\u4F1A\u513F\u80FD\u8BA8\u8BBA\u51FA\u6765\u7684\uFF0C\u6211\u4F1A\u7ED9\u51FA\u4E00\u4E2A\u601D\u8DEF\u3002\u53E6\u5916\uFF0C\u8FD8\u6709\u65B9\u6CD5\u8BBA\uFF0C\u5386\u53F2\u89C2\uFF0C\u8FD9\u4E9B\u5927\u7684\u95EE\u9898\uFF0C\u6211\u5148\u7ED9\u5927\u5BB6\u63D0\u524D\u8C08\u8BBA\u4E00\u4E0B\u3002\u7136\u540E\uFF0C\u5927\u5BB6\u90FD\u53EF\u4EE5\u5C31\u4E00\u4E9B\u95EE\u9898\u4EA4\u6D41\u3002\u6216\u8005\u662F\u4F60\u624B\u5934\u4E0A\u76F8\u5173\u7684\u4E00\u4E9B\u8D44\u6599\uFF0C\u4E5F\u53EF\u4EE5\u53D1\u4E0A\u6765\u3002</p><p>\u6211\u6B63\u5728\u5199\u8FD9\u4E2A\u4E1C\u897F\uFF0C\u56E0\u4E3A\u8FD9\u4E2A\u8BFE\u9898\u592A\u5B8F\u5927\uFF0C\u51E0\u4E4E\u662F\u6CA1\u6709\u8FB9\u754C\u7684\u4E00\u4E2A\u4E3B\u9898\uFF0C\u8FD9\u5728\u5B66\u672F\u4E0A\u662F\u4E00\u4E2A\u5927\u5FCC\uFF0C\u5199\u4E1C\u897F\u80FD\u4EE5\u8FD9\u6837\u4E00\u4E2A\u8303\u56F4\u53BB\u5199\uFF0C\u662F\u5F88\u8981\u547D\u7684\uFF0C\u53EF\u4EE5\u8BF4\u6709\u65F6\u5019\u6700\u7EC8\u4F1A\u6CA1\u6709\u4E00\u4E2A\u96C6\u4E2D\u7684\u4E3B\u9898\uFF0C\u4F1A\u5199\u7684\u5F88\u6563\u6F2B\u3002\u4F46\u662F\u6211\u4F1A\u6709\u4E00\u4E9B\u65B9\u6CD5\uFF0C\u6216\u8005\u81EA\u5DF1\u5BF9\u4E3B\u9898\u7684\u4E00\u4E2A\u9650\u5B9A\uFF0C\u6211\u89C9\u5F97\u8BA8\u8BBA\u95EE\u9898\u4E00\u5B9A\u8981\u4E86\u89E3\u6211\u5199\u6587\u660E\u53F2\u4E3B\u9898\u7684\u4E00\u4E9B\u9650\u5B9A\uFF0C\u8FD9\u4E2A\u662F\u975E\u5E38\u91CD\u8981\u7684\u3002\u5982\u679C\u5927\u5BB6\u4E0D\u4E86\u89E3\u8FD9\u4E2A\uFF0C\u5C31\u8BA8\u8BBA\u4E0D\u51FA\u7ED3\u679C\u3002\u8FD9\u662F\u6211\u4EEC\u5728\u5176\u4ED6\u7FA4\u91CC\u5E38\u89C1\u7684\u73B0\u8C61\uFF0C\u6211\u662F\u8981\u575A\u6301\u5728\u4E00\u4E2A\u9650\u5B9A\u7684\u89C6\u89D2\u4E0B\u53BB\u8C08\u8BBA\u95EE\u9898\u7684\u3002</p><p>\u4ECA\u5929\u5927\u5BB6\u77E5\u9053\uFF0C\u5728\u5B66\u672F\u4E0A\uFF0C\u73B0\u5728\u5DF2\u7ECF\u5F88\u6DF7\u4E71\u4E86\uFF0C\u8FD9\u662F\u4E00\u4E2A\u73B0\u4EE3\u548C\u540E\u73B0\u4EE3\u601D\u60F3\u628A\u63A7\u7684\u4E00\u4E2A\u5B66\u672F\u8BDD\u8BED\u65F6\u4EE3\uFF0C\u4F60\u8981\u901A\u8FC7\u73B0\u4EE3\u6216\u8005\u540E\u73B0\u4EE3\u7684\u89C6\u89D2\u53BB\u8C08\u8BBA\u95EE\u9898\uFF0C\u53EF\u80FD\u5C31\u6F2B\u65E0\u8FB9\u9645\u4E86\uFF0C\u5C31\u6CA1\u6709\u4E00\u4E2A\u6838\u5FC3\u4E86\u3002\u6240\u4EE5\u6211\u8FD8\u662F\u8981\u628A\u81EA\u5DF1\u7684\u8FD9\u4E2A\u4E3B\u9898\u8981\u9650\u5B9A\u4E00\u4E0B\uFF0C\u7B49\u5927\u5BB6\u4E86\u89E3\u8FD9\u4E2A\u6211\u6240\u5199\u4F5C\u7684\u8FD9\u4E2A\u601D\u8DEF\uFF0C\u89C6\u89D2\u7B49\u7B49\u4E4B\u540E\uFF0C\u6211\u4EEC\u518D\u8FDB\u884C\u4EA4\u6D41\u3002</p><p>\u6211\u8BF4\u8BDD\u6709\u4E00\u4E2A\u6BDB\u75C5\uFF0C\u4E00\u8BF4\u5C31\u662F\u4E00\u5927\u5806\uFF0C\u8BF7\u5927\u5BB6\u8C05\u89E3\uFF0C\u6B22\u8FCE\u5927\u5BB6\u79EF\u6781\u4EA4\u6D41\uFF01</p>',11),o=[c];function r(n,s){return e(),p("div",null,o)}const h=_(a,[["render",r],["__file","\u5148\u77E5-\u6587\u660E\u53F2\u5EFA\u7FA4\u4E3E\u610F\u548C\u5B97\u65E8.html.vue"]]);export{h as default};
